import { useCallback } from 'react';
import { useIntl } from 'react-intl';

import {
  CopyIcon,
  DotMenuIcon,
  ExternalLinkIcon,
} from '@dynatrace/strato-icons';

import { dqlEditorActionsMenuMessages } from './actions-menu-messages.js';
import * as styles from './ActionsMenu.sty.js';
import { Button } from '../../../buttons/button/Button.js';
import { DQL_DOCUMENTATION_URL } from '../../../core/external-links.js';
import { Menu } from '../../../navigation/menu/Menu.js';

/**
 * Slot component that enables the actions menu in the DQLEditor.
 *
 * Rendering this component as a child of `DQLEditor` displays a kebab menu
 * with built-in actions (Copy query, Open documentation).
 * @public
 */
// TODO (APPDEV-17376): Introduce ActionsMenuProps with `children` to support custom menu items rendered between the built-in actions.
export const ActionsMenu = (): null => null;
(ActionsMenu as typeof ActionsMenu & { displayName: string }).displayName =
  'DQLEditor.ActionsMenu';

/**
 * Props for the `ActionsMenuInternal` component.
 * @internal
 */
export interface ActionsMenuInternalProps {
  /**
   * Returns the editor's current content, copied to clipboard when the copy action is triggered.
   */
  getValue: () => string;
  /**
   * The editor's size variant affecting the trigger button and positioning.
   */
  size: 'default' | 'condensed';
}

/**
 * Internal component that renders the DQLEditor actions menu.
 * @internal
 */
export const ActionsMenuInternal = ({
  getValue,
  size,
}: ActionsMenuInternalProps) => {
  const intl = useIntl();
  // getValue() is called at copy time (not at render time) so it always reads
  // the current editor content from the ref, regardless of re-renders.
  const copyToClipboard = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(getValue());
    } catch {
      // For now, we silently ignore clipboard write errors.
    }
  }, [getValue]);

  return (
    <div className={styles.actionsMenuWrapper({ size })}>
      <Menu>
        <Menu.Trigger>
          <Button
            variant="default"
            size={size}
            aria-label={intl.formatMessage(
              dqlEditorActionsMenuMessages.triggerLabel,
            )}
            data-dt-name="OpenActionsMenu"
          >
            <Button.Prefix>
              <DotMenuIcon />
            </Button.Prefix>
          </Button>
        </Menu.Trigger>
        <Menu.Content>
          <Menu.Group>
            <Menu.Item
              onSelect={() => {
                copyToClipboard().catch(() => void 0);
              }}
              data-dt-name="CopyQuery"
            >
              <Menu.Prefix>
                <CopyIcon />
              </Menu.Prefix>
              {intl.formatMessage(dqlEditorActionsMenuMessages.copyQuery)}
            </Menu.Item>
          </Menu.Group>
          <Menu.Group>
            <Menu.Link
              href={DQL_DOCUMENTATION_URL}
              target="_blank"
              rel="noopener noreferrer"
              data-dt-name="OpenDocumentation"
            >
              <Menu.Prefix>
                <ExternalLinkIcon />
              </Menu.Prefix>
              {intl.formatMessage(
                dqlEditorActionsMenuMessages.openDocumentation,
              )}
            </Menu.Link>
          </Menu.Group>
        </Menu.Content>
      </Menu>
    </div>
  );
};
